---游戏重启控制器
local LxBehaviour = require("LApp.component.LxBehaviour")
---@class LxRestartCtrl:LxBehaviour
local LxRestartCtrl = classX("LxRestartCtrl", LxBehaviour)

local PJXUI = PJXUI
local PJXGameMgr = PJXCenter.GameMgr

local _TIMER_ID = {
    progress = 1
}

local _Steps = {
    None = 0,
    Prepare = 1,
    Restart = 2,
    UnloadBundle = 3,
    Done = 9
}

function LxRestartCtrl:Initialize()
    LxBehaviour.Initialize(self)

    self._step = _Steps.None
end

function LxRestartCtrl:Dispose()

    LxBehaviour.Dispose(self)
end

---@region 重启流程

function LxRestartCtrl:IsRestarting()
    return self._step ~= _Steps.None or self._step == _Steps.Done
end

function LxRestartCtrl:OnPrepareRestart()
    self._step = _Steps.Prepare

    MgrCenter.NetworkMgr:StopConnect("restart")
    CardEHT.ManagerCenter.GameMgr:SetGameEnvVar("GameReady", "true")
    PJXUI.UnZipUI.Instance:Show()
    PJXUI.UnZipUI.Instance:UpdateLoadingProgress(0)
    self._uiProgress = 0
    self._totalProgress = 0.95
    self:StartTimer(_TIMER_ID.progress, 0, false , -1, function()
        self:OnUpdateProgress()
    end)


end


function LxRestartCtrl:OnUpdateProgress()
    local time = self._uiProgress + Time.deltaTime
    local progress = time / 5

    if progress > self._totalProgress   then
        progress = self._totalProgress
    end

    self._uiProgress = time

    PJXUI.UnZipUI.Instance:UpdateLoadingProgress(progress)
end

function LxRestartCtrl:DoRestartGame()
    self._step = _Steps.Restart

    self:StopTimer(_TIMER_ID.progress)
    PJXUI.UnZipUI.Instance:UpdateLoadingProgress(1)

    if CS.IsWebGL() then
        self:_InnerWebGLRestart()
    else
        self:_InnerNormalRestart()
    end
end

function LxRestartCtrl:_InnerNormalRestart()
    MgrCenter.NetworkMgr:StopConnect("restart")
    --不延迟一帧会造成宿主语言的堆栈异常
    --timer 会在结束的时候自动回收，此处特别写
    ---清理http
    MgrCenter.HttpMgr:ClearAllHttps()

    MgrCenter.TimerMgr:ClearAllTimers()

    LxTimer.ClearTimer()

    local timer = LxNFrameTimer.New(function()
        ---为热重载，清理持有的资源引用
        MgrCenter.ComponentMgr:ClearForHotReload()
        ---清理音频
        MgrCenter.SoundMgr:ClearAllSounds()
        ---清理持有的资源引用
        MgrCenter.ResourceMgr:ClearAllAssets()
        ---清理http
        MgrCenter.HttpMgr:ClearAllHttps()

        MgrCenter.TimerMgr:ClearAllTimers()


        if gLxMain ~= nil then
            gLxMain:Exit()
        end
        if gLxLauncher ~= nil then
            gLxLauncher:Restart()
        end
    end, nil, 1)
    timer:Start()
end

function LxRestartCtrl:_InnerWebGLRestart()
    MgrCenter.NetworkMgr:StopConnect("restart")
    --不延迟一帧会造成宿主语言的堆栈异常
    --timer 会在结束的时候自动回收，此处特别写
    ---清理http
    MgrCenter.HttpMgr:ClearAllHttps()

    MgrCenter.TimerMgr:ClearAllTimers()

    LxTimer.ClearTimer()

    local timer = LxNFrameTimer.New(function()
        ---为热重载，清理持有的资源引用
        MgrCenter.ComponentMgr:ClearForHotReload()
        ---清理音频
        MgrCenter.SoundMgr:ClearAllSounds()
        ---清理持有的资源引用
        MgrCenter.ResourceMgr:ClearAllAssets()
        ---清理http
        MgrCenter.HttpMgr:ClearAllHttps()

        MgrCenter.TimerMgr:ClearAllTimers()

        local launch = CS.FindObject("RehtGame/RootUI/UICanvas/Launch")
        if IsValid(launch) then
            launch:SetActive(true)
        end
        MgrCenter.UIMgr:CleanUpWnd()

        self._step = _Steps.UnloadBundle
        ---等待C#清理内存中的 AssetBundle ， 与内置资源清单、资源清单等， 最后混掉OnRestartReload
        PJXGameMgr:SetGameRestart()

    end, nil, 1)
    timer:Start()
end

---由宿主语言调用
function LxRestartCtrl:OnRestartReload()
    if self._step ~= _Steps.UnloadBundle then
        return
    end
    self._step = _Steps.Done
    --先删除所有计时器
    MgrCenter.TimerMgr:ClearAllTimers()

    LxTimer.ClearTimer()

    --延迟1帧等待遮挡界面加载完成
    local timer = LxNFrameTimer.New(function()

        MgrCenter.TimerMgr:ClearAllTimers()

        if gLxMain ~= nil then
            gLxMain:Exit()
        end
        if gLxLauncher ~= nil then
            gLxLauncher:Restart()
        end

    end, nil, 1)
    timer:Start()
end

return LxRestartCtrl